import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges) {
        int size = (int) n;
        List<List<int[]>> adj = new ArrayList<>();
        for (int i = 0; i < size; i++) {
            adj.add(new ArrayList<>());
        }
        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            int s = (int) edge[2];
            int e = (int) edge[3];
            adj.get(u).add(new int[] {v, s, e});
        }
        long[] dist = new long[size];
        Arrays.fill(dist, Long.MAX_VALUE);
        dist[0] = 0;
        PriorityQueue<long[]> pq = new PriorityQueue<>(Comparator.comparingLong(a -> a[0]));
        pq.add(new long[] {0, 0});
        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            long time = current[0];
            int u = (int) current[1];
            if (u == size - 1) {
                return time;
            }
            if (time > dist[u]) {
                continue;
            }
            for (int[] edge : adj.get(u)) {
                int v = edge[0];
                int s = edge[1];
                int e = edge[2];
                long earliest = Math.max(time, s);
                if (earliest <= e) {
                    long new_time = earliest + 1;
                    if (new_time < dist[v]) {
                        dist[v] = new_time;
                        pq.add(new long[] {new_time, v});
                    }
                }
            }
        }
        return -1;
    }
}
